#' App Method Datasets Manifest
#'
#' Manifest table for datasets generated by
#' \code{\link{generate_app_method_datasets}}.
#'
#' @format A data frame with one row per dataset variant and columns:
#' \describe{
#'   \item{method}{App method name.}
#'   \item{dataset_type}{`complete` or `missing`.}
#'   \item{n}{Number of rows.}
#'   \item{file_rda}{Raw RDA path in `data-raw`.}
#'   \item{object_name}{Object name stored inside the `.rda` file.}
#'   \item{recommended_time_var}{Recommended time variable name.}
#'   \item{recommended_status_var}{Recommended status variable name.}
#'   \item{recommended_arm_var}{Recommended arm variable name.}
#'   \item{recommended_strata_var}{Recommended strata variable name.}
#'   \item{recommended_dep_cens_var}{Recommended dependent censoring status name.}
#' }
#' @keywords datasets
"app_method_datasets_manifest"
